## Step 8: `packages/client-generator-rest-api/src/generate-client.ts`

**Purpose:** Orchestrates the full code generation from DMMF to a single output string, then writes it to disk.

```typescript
import fs from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { generateRestApiClient } from './client-generator'
import { generateModelInterface, generateResourceClass } from './model-generator'

const FILE_HEADER = `// Generated by @prisma/client-generator-rest-api
// Do not edit this file manually.
`

export async function generateRestApiClientFile(
  dmmf: DMMF.Document,
  outputDir: string,
): Promise<void> {
  const { models, enums } = dmmf.datamodel
  const enumNames = new Set(enums.map((e) => e.name))

  const sections: string[] = [FILE_HEADER]

  // 1. Enum union types
  for (const enumDef of enums) {
    sections.push(generateEnumType(enumDef))
  }

  // 2. Model interfaces
  for (const model of models) {
    sections.push(generateModelInterface(model, enumNames))
  }

  // 3. Resource classes (not exported: used only by RestApiClient)
  for (const model of models) {
    sections.push(generateResourceClass(model, enumNames))
  }

  // 4. Top-level RestApiClient class
  sections.push(generateRestApiClient(models))

  const content = sections.join('\n\n') + '\n'

  await fs.mkdir(outputDir, { recursive: true })
  await fs.writeFile(path.join(outputDir, 'client.ts'), content, 'utf-8')
}

// Generates a TypeScript string union type for a Prisma enum.
// e.g. export type Role = 'ADMIN' | 'USER'
function generateEnumType(enumDef: DMMF.DatamodelEnum): string {
  const values = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${enumDef.name} = ${values}`
}
```

**Design notes:**
- Enums are emitted as `type` string unions rather than `const` objects. This is appropriate for a REST API client because enum values are serialised as strings over HTTP, and string union types provide better type narrowing.
- The `fs.mkdir` with `{ recursive: true }` ensures the output directory exists without needing `fs-extra`.
- The file is intentionally not deleted before writing, matching the simple generator pattern (the generator overwrites `client.ts` in place).

---

## Step 9: `packages/client-generator-rest-api/src/generator.ts`

**Purpose:** Implements the `Generator` interface. Minimal and focused, analogous to `PrismaClientTsGenerator` in `client-generator-ts`.

```typescript
import type { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'
import { parseEnvValue } from '@prisma/internals'

import { generateRestApiClientFile } from './generate-client'

const MISSING_OUTPUT_ERROR = `An output path is required for the \`prisma-client-rest-api\` generator. Please provide an output path in your schema file:

generator restApi {
  provider = "prisma-client-rest-api"
  output   = "../src/generated/rest-client"
}

Note: the output path is relative to the schema directory.
`

function resolveOutputPath(config: GeneratorConfig): string {
  if (!config.output) {
    throw new Error(MISSING_OUTPUT_ERROR)
  }
  return parseEnvValue(config.output)
}

export class RestApiGenerator implements Generator {
  readonly name = 'prisma-client-rest-api'

  getManifest(config: GeneratorConfig): Promise<GeneratorManifest> {
    return Promise.resolve({
      prettyName: 'Prisma REST API Client',
      defaultOutput: resolveOutputPath(config),
      requiresEngines: [],
    })
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = resolveOutputPath(options.generator)
    await generateRestApiClientFile(options.dmmf, outputDir)
  }
}
```

**Key decisions:**
- No `requiresEngineVersion` since no query engine is needed
- No `version` in manifest — this package has no published version to verify
- `resolveOutputPath` is extracted (same pattern as `getOutputPath` in `client-generator-ts`) to share between `getManifest` and `generate`
- Private fields (`#field` syntax) are not needed here since there is no per-instance mutable state (unlike `PrismaClientJsGenerator` which caches the resolved client path)

---

## Step 10: `packages/client-generator-rest-api/src/index.ts`

**Purpose:** Public API surface for the package. No barrel re-exports of internals.

```typescript
export { RestApiGenerator } from './generator'
export { generateRestApiClientFile } from './generate-client'
```

The `generateRestApiClientFile` export is intentional: it allows test helpers and external callers to invoke code generation directly without going through the generator protocol (same pattern as exporting `generateClient` from `client-generator-ts`).

---

## Step 11: Modify `tsconfig.build.bundle.json`

Add the path alias entry within the `paths` map:

```json
"@prisma/client-generator-rest-api": ["./packages/client-generator-rest-api/src"]
```

This must appear alongside the other `@prisma/client-generator-*` entries.

---

## Step 12: Modify `.github/workflows/test-template.yml`

Add the new step immediately after the `client-generator-registry` step (line ~591), within the `client-packages` job:

```yaml
      - run: pnpm run test
        name: 'client-generator-rest-api'
        working-directory: packages/client-generator-rest-api
```

---

## Step 13: Test Strategy

### Test file: `packages/client-generator-rest-api/tests/type-mapper.test.ts`

Unit tests for the pure mapping function, verifiable without any file I/O or generator protocol:

