# Plan: `@prisma/client-generator-rest-api`

## Context

Add a new Prisma generator package to the monorepo that reads a Prisma schema's DMMF and outputs a single `client.ts` file containing TypeScript interfaces, string-union enum types, per-model `*Resource` classes (with typed CRUD methods over `fetch`), and a top-level `RestApiClient` class that composes all resource accessors.

This follows the same in-process `Generator` interface pattern used by `client-generator-js` and `client-generator-ts`; no standalone binary or JSON-RPC `generatorHandler` bin entry is needed.

---

## Files to Create

```
packages/client-generator-rest-api/
├── package.json
├── tsconfig.json
├── tsconfig.build.json
├── helpers/
│   └── build.ts
└── src/
    ├── index.ts
    ├── generator.ts
    ├── generate-client.ts
    ├── type-mapper.ts
    ├── model-generator.ts
    ├── client-generator.ts
    ├── type-mapper.test.ts
    ├── model-generator.test.ts
    └── generate-client.test.ts
```

## Files to Modify

- `tsconfig.build.bundle.json` — add path alias entry
- `.github/workflows/test-template.yml` — add CI step to `client-packages` job

---

## Step-by-Step Implementation

### 1. `package.json`

```json
{
  "name": "@prisma/client-generator-rest-api",
  "version": "0.0.0",
  "description": "This package is intended for Prisma's internal use",
  "main": "dist/index.js",
  "module": "dist/index.mjs",
  "types": "dist/index.d.ts",
  "exports": {
    ".": {
      "require": { "types": "./dist/index.d.ts", "default": "./dist/index.js" },
      "import": { "types": "./dist/index.d.mts", "default": "./dist/index.mjs" }
    }
  },
  "repository": {
    "type": "git",
    "url": "https://github.com/prisma/prisma.git",
    "directory": "packages/client-generator-rest-api"
  },
  "license": "Apache-2.0",
  "dependencies": {
    "@prisma/dmmf": "workspace:*",
    "@prisma/generator": "workspace:*",
    "@prisma/internals": "workspace:*"
  },
  "scripts": {
    "dev": "DEV=true tsx helpers/build.ts",
    "build": "tsx helpers/build.ts",
    "prepublishOnly": "pnpm run build",
    "test": "vitest run --testTimeout 30000"
  },
  "files": ["dist"],
  "sideEffects": false
}
```

No `@prisma/engines-version` needed — this generator requires no query engine.

---

### 2. `tsconfig.json`

```json
{
  "extends": "../../tsconfig.json",
  "include": ["./**/*"]
}
```

### 3. `tsconfig.build.json`

```json
{
  "extends": "../../tsconfig.build.regular.json",
  "compilerOptions": {
    "outDir": "dist",
    "rootDir": "src"
  },
  "include": ["src"]
}
```

### 4. `helpers/build.ts`

```typescript
import { build } from '../../../helpers/compile/build'
import { adapterConfig } from '../../../helpers/compile/configs'

void build(adapterConfig)
```

---

### 5. `src/type-mapper.ts`

Pure functions mapping DMMF field types to TypeScript type strings. Isolated for unit testing.

```typescript
import type * as DMMF from '@prisma/dmmf'

/**
 * Maps a DMMF scalar type name to the corresponding TypeScript type string.
 * Relation fields (kind === 'object') are handled by the caller.
 */
export function mapScalarTypeToTs(dmmfType: string): string {
  switch (dmmfType) {
    case 'String':   return 'string'
    case 'Int':
    case 'Float':    return 'number'
    case 'Boolean':  return 'boolean'
    case 'DateTime': return 'Date'
    case 'Json':     return 'unknown'
    // Serialised as strings over HTTP to avoid precision loss
    case 'Decimal':
    case 'BigInt':
    case 'Bytes':    return 'string'
    default:         return 'unknown'
  }
}

/**
 * Derives the TypeScript type string for a DMMF field, applying list
 * wrappers, nullability, enum type pass-through, and relation type pass-through.
 */
export function mapFieldToTs(field: DMMF.Field, enumNames: ReadonlySet<string>): string {
  let baseType: string

  if (field.kind === 'enum') {
    baseType = field.type
  } else if (field.kind === 'object') {
    baseType = field.type
  } else if (field.kind === 'unsupported') {
    baseType = 'unknown'
  } else {
    baseType = mapScalarTypeToTs(field.type)
  }

  const tsType = field.isList ? `${baseType}[]` : baseType
  const isNullable = !field.isRequired && !field.isList
  return isNullable ? `${tsType} | null` : tsType
}
```

---

### 6. `src/model-generator.ts`

Emits per-model code: the TypeScript interface, the `*Resource` class with five CRUD methods, and helper lines used inside `RestApiClient`.

Key design decisions:
- Resource path: PascalCase model name → kebab-case + `s` suffix (e.g. `UserPost` → `user-posts`)
- ID field: first field where `isId === true`; falls back to first field named `'id'`
- `create` data type: `Omit<Model, 'idFieldName'>` (excludes auto-generated id)
- Relation fields rendered with the `?` optional modifier in the interface (they are not always fetched by the REST API)
- HTTP calls centralised in a private `#request` method; relies on global `fetch` (Node 18+, all browsers)
- Private fields use `#field` syntax per repo conventions

```typescript
import type * as DMMF from '@prisma/dmmf'
import { mapFieldToTs } from './type-mapper'

function toAccessorName(modelName: string): string {
  return modelName.charAt(0).toLowerCase() + modelName.slice(1)
}

function toResourceClassName(modelName: string): string {
  return `${modelName}Resource`
}

function toResourcePath(modelName: string): string {
  const kebab = modelName.replace(/([A-Z])/g, (ch, _, offset) =>
    offset === 0 ? ch.toLowerCase() : `-${ch.toLowerCase()}`,
  )
  return `${kebab}s`
}

function findIdField(model: DMMF.Model): DMMF.Field | undefined {
  return model.fields.find((f) => f.isId) ?? model.fields.find((f) => f.name === 'id')
}

export function generateModelInterface(model: DMMF.Model, enumNames: ReadonlySet<string>): string {
  const lines = model.fields.map((field) => {
    const tsType = mapFieldToTs(field, enumNames)
    const opt = field.kind === 'object' ? '?' : ''
    return `  ${field.name}${opt}: ${tsType}`
  })
  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

export function generateResourceClass(model: DMMF.Model, enumNames: ReadonlySet<string>): string {
  const className = toResourceClassName(model.name)
  const iface = model.name
  const idField = findIdField(model)
  const whereType = idField
    ? `{ ${idField.name}: ${mapFieldToTs(idField, enumNames)} }`
    : '{ id: unknown }'
  const idName = idField?.name ?? 'id'
  const createDataType = idField ? `Omit<${iface}, '${idName}'>` : iface
  const path = toResourcePath(model.name)

  return `class ${className} {
  readonly #baseUrl: string
  readonly #headers: Record<string, string>

  constructor(baseUrl: string, headers: Record<string, string>) {
    this.#baseUrl = baseUrl
    this.#headers = headers
  }

  async findMany(args?: { skip?: number; take?: number; where?: Partial<${iface}> }): Promise<${iface}[]> {
    const params = new URLSearchParams()
    if (args?.skip !== undefined) params.set('skip', String(args.skip))
    if (args?.take !== undefined) params.set('take', String(args.take))
    if (args?.where !== undefined) params.set('where', JSON.stringify(args.where))
    const qs = params.size > 0 ? \`?\${params.toString()}\` : ''
    return this.#request('GET', \`${path}\${qs}\`)
  }

  async findUnique(args: { where: ${whereType} }): Promise<${iface} | null> {
    return this.#request('GET', \`${path}/\${args.where.${idName}}\`)
  }

  async create(args: { data: ${createDataType} }): Promise<${iface}> {
    return this.#request('POST', '${path}', args.data)
  }

  async update(args: { where: ${whereType}; data: Partial<${iface}> }): Promise<${iface}> {
    return this.#request('PUT', \`${path}/\${args.where.${idName}}\`, args.data)
  }

  async delete(args: { where: ${whereType} }): Promise<${iface}> {
    return this.#request('DELETE', \`${path}/\${args.where.${idName}}\`)
  }

  async #request(method: string, path: string, body?: unknown): Promise<any> {
    const res = await fetch(\`\${this.#baseUrl}/\${path}\`, {
      method,
      headers: { 'Content-Type': 'application/json', ...this.#headers },
      body: body !== undefined ? JSON.stringify(body) : undefined,
    })
    if (!res.ok) {
      throw new Error(\`[prisma-rest-api] \${method} \${path} failed: \${res.status} \${res.statusText}\`)
    }
    return res.json()
  }
}`
}

/** Returns `  readonly user: UserResource` for use inside RestApiClient. */
export function generateClientProperty(model: DMMF.Model): string {
  return `  readonly ${toAccessorName(model.name)}: ${toResourceClassName(model.name)}`
}

/** Returns `    this.user = new UserResource(options.baseUrl, headers)` */
export function generateClientAssignment(model: DMMF.Model): string {
  return `    this.${toAccessorName(model.name)} = new ${toResourceClassName(model.name)}(options.baseUrl, headers)`
}
```

---

### 7. `src/client-generator.ts`

Emits the `RestApiClientOptions` interface and the `RestApiClient` class.

```typescript
import type * as DMMF from '@prisma/dmmf'
import { generateClientAssignment, generateClientProperty } from './model-generator'

export function generateRestApiClient(models: readonly DMMF.Model[]): string {
  const props = models.map(generateClientProperty).join('\n')
  const assignments = models.map(generateClientAssignment).join('\n')

  return `export interface RestApiClientOptions {
  baseUrl: string
  headers?: Record<string, string>
}

export class RestApiClient {
${props}

  constructor(options: RestApiClientOptions) {
    const headers = options.headers ?? {}
${assignments}
  }
}`
}
```

---

### 8. `src/generate-client.ts`

Orchestrates full code generation from `DMMF.Document` → single `client.ts` file on disk. Enums are emitted as string union types (appropriate for HTTP serialisation).

```typescript
import fs from 'node:fs/promises'
import path from 'node:path'
import type * as DMMF from '@prisma/dmmf'
import { generateRestApiClient } from './client-generator'
import { generateModelInterface, generateResourceClass } from './model-generator'

const FILE_HEADER = `// Generated by @prisma/client-generator-rest-api — do not edit manually.\n`

function generateEnumType(enumDef: DMMF.DatamodelEnum): string {
  const values = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${enumDef.name} = ${values}`
}

export async function generateRestApiClientFile(dmmf: DMMF.Document, outputDir: string): Promise<void> {
  const { models, enums } = dmmf.datamodel
  const enumNames = new Set(enums.map((e) => e.name))

  const sections: string[] = [FILE_HEADER]
  for (const enumDef of enums) sections.push(generateEnumType(enumDef))
  for (const model of models) sections.push(generateModelInterface(model, enumNames))
  for (const model of models) sections.push(generateResourceClass(model, enumNames))
  sections.push(generateRestApiClient(models))

  const content = sections.join('\n\n') + '\n'
  await fs.mkdir(outputDir, { recursive: true })
  await fs.writeFile(path.join(outputDir, 'client.ts'), content, 'utf-8')
}
```

