import type { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'
import { parseEnvValue } from '@prisma/internals'
import { generateRestApiClientFile } from './generate-client'

const MISSING_OUTPUT_ERROR =
  `An output path is required for the \`prisma-client-rest-api\` generator. ` +
  `Please add \`output = "../src/generated"\` to the generator block.`

function getOutputPath(config: GeneratorConfig): string {
  if (!config.output) throw new Error(MISSING_OUTPUT_ERROR)
  return parseEnvValue(config.output)
}

export class RestApiGenerator implements Generator {
  readonly name = 'prisma-client-rest-api'

  getManifest(config: GeneratorConfig): Promise<GeneratorManifest> {
    return Promise.resolve({
      prettyName: 'Prisma REST API Client',
      defaultOutput: getOutputPath(config),
      requiresEngines: [],
    })
  }

  async generate(options: GeneratorOptions): Promise<void> {
    await generateRestApiClientFile(options.dmmf, getOutputPath(options.generator))
  }
}
