### 6. `src/model-generator.ts`

Emits per-model code: the TypeScript interface, the `*Resource` class with five CRUD methods, and helper lines used inside `RestApiClient`.

Key design decisions:
- Resource path: PascalCase model name → kebab-case + `s` suffix (e.g. `UserPost` → `user-posts`)
- ID field: first field where `isId === true`; falls back to first field named `'id'`
- `create` data type: `Omit<Model, 'idFieldName'>` (excludes auto-generated id)
- Relation fields rendered with the `?` optional modifier in the interface (they are not always fetched by the REST API)
- HTTP calls centralised in a private `#request` method; relies on global `fetch` (Node 18+, all browsers)
- Private fields use `#field` syntax per repo conventions

```typescript
import type * as DMMF from '@prisma/dmmf'
import { mapFieldToTs } from './type-mapper'

function toAccessorName(modelName: string): string {
  return modelName.charAt(0).toLowerCase() + modelName.slice(1)
}

function toResourceClassName(modelName: string): string {
  return `${modelName}Resource`
}

function toResourcePath(modelName: string): string {
  const kebab = modelName.replace(/([A-Z])/g, (ch, _, offset) =>
    offset === 0 ? ch.toLowerCase() : `-${ch.toLowerCase()}`,
  )
  return `${kebab}s`
}

function findIdField(model: DMMF.Model): DMMF.Field | undefined {
  return model.fields.find((f) => f.isId) ?? model.fields.find((f) => f.name === 'id')
}

export function generateModelInterface(model: DMMF.Model, enumNames: ReadonlySet<string>): string {
  const lines = model.fields.map((field) => {
    const tsType = mapFieldToTs(field, enumNames)
    const opt = field.kind === 'object' ? '?' : ''
    return `  ${field.name}${opt}: ${tsType}`
  })
  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

export function generateResourceClass(model: DMMF.Model, enumNames: ReadonlySet<string>): string {
  const className = toResourceClassName(model.name)
  const iface = model.name
  const idField = findIdField(model)
  const whereType = idField
    ? `{ ${idField.name}: ${mapFieldToTs(idField, enumNames)} }`
    : '{ id: unknown }'
  const idName = idField?.name ?? 'id'
  const createDataType = idField ? `Omit<${iface}, '${idName}'>` : iface
  const path = toResourcePath(model.name)

  return `class ${className} {
  readonly #baseUrl: string
  readonly #headers: Record<string, string>

  constructor(baseUrl: string, headers: Record<string, string>) {
    this.#baseUrl = baseUrl
    this.#headers = headers
  }

  async findMany(args?: { skip?: number; take?: number; where?: Partial<${iface}> }): Promise<${iface}[]> {
    const params = new URLSearchParams()
    if (args?.skip !== undefined) params.set('skip', String(args.skip))
    if (args?.take !== undefined) params.set('take', String(args.take))
    if (args?.where !== undefined) params.set('where', JSON.stringify(args.where))
    const qs = params.size > 0 ? \`?\${params.toString()}\` : ''
    return this.#request('GET', \`${path}\${qs}\`)
  }

  async findUnique(args: { where: ${whereType} }): Promise<${iface} | null> {
    return this.#request('GET', \`${path}/\${args.where.${idName}}\`)
  }

  async create(args: { data: ${createDataType} }): Promise<${iface}> {
    return this.#request('POST', '${path}', args.data)
  }

  async update(args: { where: ${whereType}; data: Partial<${iface}> }): Promise<${iface}> {
    return this.#request('PUT', \`${path}/\${args.where.${idName}}\`, args.data)
  }

  async delete(args: { where: ${whereType} }): Promise<${iface}> {
    return this.#request('DELETE', \`${path}/\${args.where.${idName}}\`)
  }

  async #request(method: string, path: string, body?: unknown): Promise<any> {
    const res = await fetch(\`\${this.#baseUrl}/\${path}\`, {
      method,
      headers: { 'Content-Type': 'application/json', ...this.#headers },
      body: body !== undefined ? JSON.stringify(body) : undefined,
    })
    if (!res.ok) {
      throw new Error(\`[prisma-rest-api] \${method} \${path} failed: \${res.status} \${res.statusText}\`)
    }
    return res.json()
  }
}`
}

/** Returns `  readonly user: UserResource` for use inside RestApiClient. */
export function generateClientProperty(model: DMMF.Model): string {
  return `  readonly ${toAccessorName(model.name)}: ${toResourceClassName(model.name)}`
}

/** Returns `    this.user = new UserResource(options.baseUrl, headers)` */
export function generateClientAssignment(model: DMMF.Model): string {
  return `    this.${toAccessorName(model.name)} = new ${toResourceClassName(model.name)}(options.baseUrl, headers)`
}
```

