### 8. `src/generate-client.ts`

Orchestrates full code generation from `DMMF.Document` → single `client.ts` file on disk. Enums are emitted as string union types (appropriate for HTTP serialisation).

```typescript
import fs from 'node:fs/promises'
import path from 'node:path'
import type * as DMMF from '@prisma/dmmf'
import { generateRestApiClient } from './client-generator'
import { generateModelInterface, generateResourceClass } from './model-generator'

const FILE_HEADER = `// Generated by @prisma/client-generator-rest-api — do not edit manually.\n`

function generateEnumType(enumDef: DMMF.DatamodelEnum): string {
  const values = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${enumDef.name} = ${values}`
}

export async function generateRestApiClientFile(dmmf: DMMF.Document, outputDir: string): Promise<void> {
  const { models, enums } = dmmf.datamodel
  const enumNames = new Set(enums.map((e) => e.name))

  const sections: string[] = [FILE_HEADER]
  for (const enumDef of enums) sections.push(generateEnumType(enumDef))
  for (const model of models) sections.push(generateModelInterface(model, enumNames))
  for (const model of models) sections.push(generateResourceClass(model, enumNames))
  sections.push(generateRestApiClient(models))

  const content = sections.join('\n\n') + '\n'
  await fs.mkdir(outputDir, { recursive: true })
  await fs.writeFile(path.join(outputDir, 'client.ts'), content, 'utf-8')
}
```

