### 7. `src/client-generator.ts`

Emits the `RestApiClientOptions` interface and the `RestApiClient` class.

```typescript
import type * as DMMF from '@prisma/dmmf'
import { generateClientAssignment, generateClientProperty } from './model-generator'

export function generateRestApiClient(models: readonly DMMF.Model[]): string {
  const props = models.map(generateClientProperty).join('\n')
  const assignments = models.map(generateClientAssignment).join('\n')

  return `export interface RestApiClientOptions {
  baseUrl: string
  headers?: Record<string, string>
}

export class RestApiClient {
${props}

  constructor(options: RestApiClientOptions) {
    const headers = options.headers ?? {}
${assignments}
  }
}`
}
```

