import type * as DMMF from '@prisma/dmmf'
import { mapScalarTypeToTs, mapFieldToTs } from './type-mapper'

// Build a minimal DMMF Field fixture
function field(overrides: Partial<DMMF.Field>): DMMF.Field {
  return {
    kind: 'scalar', name: 'x', isRequired: true, isList: false,
    isUnique: false, isId: false, isReadOnly: false, hasDefaultValue: false,
    type: 'String',
    ...overrides,
  } as DMMF.Field
}

describe('mapScalarTypeToTs', () => {
  test.each([
    ['String', 'string'], ['Int', 'number'], ['Float', 'number'],
    ['Boolean', 'boolean'], ['DateTime', 'Date'], ['Json', 'unknown'],
    ['Decimal', 'string'], ['BigInt', 'string'], ['Bytes', 'string'],
    ['Unknown', 'unknown'],
  ])('%s → %s', (dmmf, ts) => expect(mapScalarTypeToTs(dmmf)).toBe(ts))
})

describe('mapFieldToTs', () => {
  const noEnums = new Set<string>()
  test('required scalar → no null', () => expect(mapFieldToTs(field({ type: 'Int' }), noEnums)).toBe('number'))
  test('optional scalar → | null', () => expect(mapFieldToTs(field({ isRequired: false }), noEnums)).toBe('string | null'))
  test('list field → array, no null', () => expect(mapFieldToTs(field({ isList: true, isRequired: false }), noEnums)).toBe('string[]'))
  test('enum field → enum name', () => expect(mapFieldToTs(field({ kind: 'enum', type: 'Role' }), new Set(['Role']))).toBe('Role'))
  test('object (relation) → model name', () => expect(mapFieldToTs(field({ kind: 'object', type: 'Post' }), noEnums)).toBe('Post'))
  test('unsupported → unknown', () => expect(mapFieldToTs(field({ kind: 'unsupported' }), noEnums)).toBe('unknown'))
})
