### 5. `src/type-mapper.ts`

Pure functions mapping DMMF field types to TypeScript type strings. Isolated for unit testing.

```typescript
import type * as DMMF from '@prisma/dmmf'

/**
 * Maps a DMMF scalar type name to the corresponding TypeScript type string.
 * Relation fields (kind === 'object') are handled by the caller.
 */
export function mapScalarTypeToTs(dmmfType: string): string {
  switch (dmmfType) {
    case 'String':   return 'string'
    case 'Int':
    case 'Float':    return 'number'
    case 'Boolean':  return 'boolean'
    case 'DateTime': return 'Date'
    case 'Json':     return 'unknown'
    // Serialised as strings over HTTP to avoid precision loss
    case 'Decimal':
    case 'BigInt':
    case 'Bytes':    return 'string'
    default:         return 'unknown'
  }
}

/**
 * Derives the TypeScript type string for a DMMF field, applying list
 * wrappers, nullability, enum type pass-through, and relation type pass-through.
 */
export function mapFieldToTs(field: DMMF.Field, enumNames: ReadonlySet<string>): string {
  let baseType: string

  if (field.kind === 'enum') {
    baseType = field.type
  } else if (field.kind === 'object') {
    baseType = field.type
  } else if (field.kind === 'unsupported') {
    baseType = 'unknown'
  } else {
    baseType = mapScalarTypeToTs(field.type)
  }

  const tsType = field.isList ? `${baseType}[]` : baseType
  const isNullable = !field.isRequired && !field.isList
  return isNullable ? `${tsType} | null` : tsType
}
```

