import type { DMMF } from '@prisma/dmmf'

import { resourceClassName } from './model-generator'

/**
 * Emits the `RestApiClientOptions` interface and the `RestApiClient` class
 * that composes all per-model resource accessors.
 */
export function generateRestApiClient(models: readonly DMMF.Model[]): string {
  const accessors = models
    .map((m) => {
      const prop = m.name.charAt(0).toLowerCase() + m.name.slice(1)
      return `  readonly ${prop}: ${resourceClassName(m.name)}`
    })
    .join('\n')

  const assignments = models
    .map((m) => {
      const prop = m.name.charAt(0).toLowerCase() + m.name.slice(1)
      return `    this.${prop} = new ${resourceClassName(m.name)}(options.baseUrl, options.headers ?? {})`
    })
    .join('\n')

  return `export interface RestApiClientOptions {
  /** Base URL of the REST API server, e.g. \`https://api.example.com\` */
  baseUrl: string
  /** Optional default headers sent with every request */
  headers?: Record<string, string>
}

export class RestApiClient {
${accessors}

  constructor(options: RestApiClientOptions) {
${assignments}
  }
}`
}

