import path from 'node:path'

import type { DMMF } from '@prisma/dmmf'

import { generateRestApiClient } from './client-generator'
import { generateModelInterface, generateResourceClass } from './model-generator'

const FILE_HEADER = '// Generated by @prisma/client-generator-rest-api — do not edit manually.\n'

/**
 * Generates an enum as a TypeScript string-union type.
 * e.g. `Role` with values `ADMIN`, `USER` → `export type Role = 'ADMIN' | 'USER'`
 */
function generateEnum(dmmfEnum: DMMF.DatamodelEnum): string {
  const values = dmmfEnum.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${dmmfEnum.name} = ${values}`
}

/**
 * Generates the full REST API client source file content for the given DMMF
 * document and writes it to `<outputDir>/client.ts`.
 */
export async function generateRestApiClientFile(dmmf: DMMF.Document, outputDir: string): Promise<void> {
  const sections: string[] = [FILE_HEADER]

  // Enums
  for (const e of dmmf.datamodel.enums) {
    sections.push(generateEnum(e))
  }

  // Model interfaces
  for (const model of dmmf.datamodel.models) {
    sections.push(generateModelInterface(model))
  }

  // Resource classes (not exported — used only by RestApiClient)
  for (const model of dmmf.datamodel.models) {
    sections.push(generateResourceClass(model))
  }

  // Top-level client class
  sections.push(generateRestApiClient(dmmf.datamodel.models))

  const content = sections.join('\n\n') + '\n'

  await fs.mkdir(outputDir, { recursive: true })
  await fs.writeFile(path.join(outputDir, 'client.ts'), content, 'utf-8')
}

