import type { DMMF } from '@prisma/dmmf'
import { describe, expect, it } from 'vitest'

import { mapScalarToTsType } from './type-mapper'

function field(overrides: Partial<DMMF.Field> & { type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    name: 'field',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  } as DMMF.Field
}

describe('mapScalarToTsType', () => {
  it.each([
    ['String', 'string'],
    ['Boolean', 'boolean'],
    ['Int', 'number'],
    ['Float', 'number'],
    ['DateTime', 'Date'],
    ['Decimal', 'string'],
    ['BigInt', 'string'],
    ['Bytes', 'string'],
    ['Json', 'unknown'],
  ])('maps scalar %s → %s (required)', (prismaType, expected) => {
    expect(mapScalarToTsType(field({ type: prismaType }))).toBe(expected)
  })

  it('appends `| null` for optional scalar fields', () => {
    expect(mapScalarToTsType(field({ type: 'String', isRequired: false }))).toBe('string | null')
  })

  it('wraps in array for list fields', () => {
    expect(mapScalarToTsType(field({ type: 'Int', isList: true }))).toBe('number[]')
  })

  it('does not append null for required list fields', () => {
    expect(mapScalarToTsType(field({ type: 'String', isList: true, isRequired: true }))).toBe('string[]')
  })

  it('returns enum name for enum fields', () => {
    expect(mapScalarToTsType(field({ kind: 'enum', type: 'Role' }))).toBe('Role')
  })

  it('returns model name for relation fields', () => {
    expect(mapScalarToTsType(field({ kind: 'object', type: 'Post' }))).toBe('Post')
  })

  it('returns `unknown` for unsupported fields', () => {
    expect(mapScalarToTsType(field({ kind: 'unsupported', type: 'geometry' }))).toBe('unknown')
  })
})

