import type { DMMF } from '@prisma/dmmf'
import { describe, expect, it } from 'vitest'

import { generateModelInterface, generateResourceClass, resourceClassName } from './model-generator'

function makeModel(overrides: Partial<DMMF.Model> & { name: string; fields: DMMF.Field[] }): DMMF.Model {
  return {
    dbName: null,
    schema: null,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
    ...overrides,
  } as DMMF.Model
}

function scalarField(name: string, type: string, opts?: Partial<DMMF.Field>): DMMF.Field {
  return {
    kind: 'scalar',
    name,
    type,
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...opts,
  } as DMMF.Field
}

const userModel = makeModel({
  name: 'User',
  fields: [
    scalarField('id', 'Int', { isId: true, hasDefaultValue: true }),
    scalarField('email', 'String', { isUnique: true }),
    scalarField('name', 'String', { isRequired: false }),
    { kind: 'object', name: 'posts', type: 'Post', isRequired: false, isList: true, isUnique: false, isId: false, isReadOnly: false, hasDefaultValue: false } as DMMF.Field,
  ],
})

describe('resourceClassName', () => {
  it('appends Resource suffix', () => {
    expect(resourceClassName('User')).toBe('UserResource')
    expect(resourceClassName('BlogPost')).toBe('BlogPostResource')
  })
})

describe('generateModelInterface', () => {
  it('emits an export interface with scalar and enum fields only', () => {
    const result = generateModelInterface(userModel)
    expect(result).toContain('export interface User {')
    expect(result).toContain('id: number')
    expect(result).toContain('email: string')
    expect(result).toContain('name?: string | null')
    // relation field should be absent
    expect(result).not.toContain('posts')
  })
})

describe('generateResourceClass', () => {
  it('generates a class named <Model>Resource', () => {
    const result = generateResourceClass(userModel)
    expect(result).toContain('class UserResource {')
  })

  it('contains all five CRUD methods', () => {
    const result = generateResourceClass(userModel)
    expect(result).toContain('async findMany(')
    expect(result).toContain('async findUnique(')
    expect(result).toContain('async create(')
    expect(result).toContain('async update(')
    expect(result).toContain('async delete(')
  })

  it('uses Omit<> on the create input for fields with defaults', () => {
    const result = generateResourceClass(userModel)
    // `id` has hasDefaultValue: true, so it should be omitted
    expect(result).toContain('Omit<User,')
    expect(result).toContain('"id"')
  })

  it('uses the lowercase-plural path in fetch calls', () => {
    const result = generateResourceClass(userModel)
    expect(result).toContain('/users')
  })

  it('uses private class fields (#baseUrl, #headers)', () => {
    const result = generateResourceClass(userModel)
    expect(result).toContain('#baseUrl')
    expect(result).toContain('#headers')
  })
})

