import type { DMMF } from '@prisma/dmmf'

/**
 * Maps a DMMF scalar field type to a TypeScript type string suitable for a
 * REST API client. Types that can't round-trip through JSON without loss
 * (Decimal, BigInt, Bytes) are represented as `string`.
 */
export function mapScalarToTsType(field: DMMF.Field): string {
  const base = scalarBaseType(field)
  const nullable = !field.isRequired ? ' | null' : ''
  return field.isList ? `${base}[]` : `${base}${nullable}`
}

function scalarBaseType(field: DMMF.Field): string {
  if (field.kind === 'enum') {
    return field.type
  }

  if (field.kind === 'object') {
    return field.type
  }

  if (field.kind === 'unsupported') {
    return 'unknown'
  }

  switch (field.type) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
      return 'number'
    case 'DateTime':
      return 'Date'
    // Decimal, BigInt, and Bytes cannot safely round-trip through JSON, so
    // they are represented as strings in the REST API client.
    case 'Decimal':
    case 'BigInt':
    case 'Bytes':
      return 'string'
    case 'Json':
      return 'unknown'
    default:
      return 'unknown'
  }
}

import type { DMMF } from '@prisma/dmmf'

import { mapScalarToTsType } from './type-mapper'

/**
 * Returns the name of the REST resource class for a given model.
 * e.g. `User` → `UserResource`
 */
export function resourceClassName(modelName: string): string {
  return `${modelName}Resource`
}

/**
 * Returns the URL path segment for a model (lowercased plural).
 * e.g. `User` → `users`
 */
function urlPath(modelName: string): string {
  return modelName.toLowerCase() + 's'
}

/**
 * Emits a TypeScript `export interface` for a DMMF model, covering all
 * scalar and enum fields (relation fields are omitted from the interface
 * since they are not part of a plain REST response by default).
 */
export function generateModelInterface(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => {
      const optional = !f.isRequired ? '?' : ''
      return `  ${f.name}${optional}: ${mapScalarToTsType(f)}`
    })
    .join('\n')

  return `export interface ${model.name} {\n${fields}\n}`
}

/**
 * Returns a TypeScript type representing the fields required to create a new
 * record. All fields that have a default value or are generated are omitted so
 * callers do not have to supply them.
 */
function createInputType(model: DMMF.Model): string {
  const omittedFields = model.fields
    .filter((f) => f.kind !== 'object' && (f.hasDefaultValue || f.isGenerated || f.isUpdatedAt))
    .map((f) => JSON.stringify(f.name))

  if (omittedFields.length === 0) {
    return model.name
  }
  return `Omit<${model.name}, ${omittedFields.join(' | ')}>`
}

/**
 * Emits a (non-exported) resource class with five async CRUD methods that
 * communicate with a REST server via the Fetch API.
 */
export function generateResourceClass(model: DMMF.Model): string {
  const path = urlPath(model.name)
  const inputType = createInputType(model)

  return `class ${resourceClassName(model.name)} {
  #baseUrl: string
  #headers: Record<string, string>

  constructor(baseUrl: string, headers: Record<string, string>) {
    this.#baseUrl = baseUrl
    this.#headers = headers
  }

  async findMany(params?: { skip?: number; take?: number; where?: Partial<${model.name}> }): Promise<${model.name}[]> {
    const query = params ? '?' + new URLSearchParams(JSON.parse(JSON.stringify(params ?? {}))).toString() : ''
    const response = await fetch(\`\${this.#baseUrl}/${path}\${query}\`, { headers: this.#headers })
    if (!response.ok) throw new Error(\`findMany ${model.name} failed: \${response.status}\`)
    return response.json() as Promise<${model.name}[]>
  }

  async findUnique(id: string | number): Promise<${model.name} | null> {
    const response = await fetch(\`\${this.#baseUrl}/${path}/\${id}\`, { headers: this.#headers })
    if (response.status === 404) return null
    if (!response.ok) throw new Error(\`findUnique ${model.name} failed: \${response.status}\`)
    return response.json() as Promise<${model.name}>
  }

  async create(data: ${inputType}): Promise<${model.name}> {
    const response = await fetch(\`\${this.#baseUrl}/${path}\`, {
      method: 'POST',
      headers: { ...this.#headers, 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!response.ok) throw new Error(\`create ${model.name} failed: \${response.status}\`)
    return response.json() as Promise<${model.name}>
  }

  async update(id: string | number, data: Partial<${inputType}>): Promise<${model.name}> {
    const response = await fetch(\`\${this.#baseUrl}/${path}/\${id}\`, {
      method: 'PUT',
      headers: { ...this.#headers, 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!response.ok) throw new Error(\`update ${model.name} failed: \${response.status}\`)
    return response.json() as Promise<${model.name}>
  }

  async delete(id: string | number): Promise<${model.name}> {
    const response = await fetch(\`\${this.#baseUrl}/${path}/\${id}\`, {
      method: 'DELETE',
      headers: this.#headers,
    })
    if (!response.ok) throw new Error(\`delete ${model.name} failed: \${response.status}\`)
    return response.json() as Promise<${model.name}>
  }
}`
}

import type { DMMF } from '@prisma/dmmf'

import { resourceClassName } from './model-generator'

/**
 * Emits the `RestApiClientOptions` interface and the `RestApiClient` class
 * that composes all per-model resource accessors.
 */
export function generateRestApiClient(models: readonly DMMF.Model[]): string {
  const accessors = models
    .map((m) => {
      const prop = m.name.charAt(0).toLowerCase() + m.name.slice(1)
      return `  readonly ${prop}: ${resourceClassName(m.name)}`
    })
    .join('\n')

  const assignments = models
    .map((m) => {
      const prop = m.name.charAt(0).toLowerCase() + m.name.slice(1)
      return `    this.${prop} = new ${resourceClassName(m.name)}(options.baseUrl, options.headers ?? {})`
    })
    .join('\n')

  return `export interface RestApiClientOptions {
  /** Base URL of the REST API server, e.g. \`https://api.example.com\` */
  baseUrl: string
  /** Optional default headers sent with every request */
  headers?: Record<string, string>
}

export class RestApiClient {
${accessors}

  constructor(options: RestApiClientOptions) {
${assignments}
  }
}`
}

import fs from 'node:fs/promises'
import path from 'node:path'

import type { DMMF } from '@prisma/dmmf'

import { generateRestApiClient } from './client-generator'
import { generateModelInterface, generateResourceClass } from './model-generator'

const FILE_HEADER = '// Generated by @prisma/client-generator-rest-api — do not edit manually.\n'

/**
 * Generates an enum as a TypeScript string-union type.
 * e.g. `Role` with values `ADMIN`, `USER` → `export type Role = 'ADMIN' | 'USER'`
 */
function generateEnum(dmmfEnum: DMMF.DatamodelEnum): string {
  const values = dmmfEnum.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${dmmfEnum.name} = ${values}`
}

/**
 * Generates the full REST API client source file content for the given DMMF
 * document and writes it to `<outputDir>/client.ts`.
 */
export async function generateRestApiClientFile(dmmf: DMMF.Document, outputDir: string): Promise<void> {
  const sections: string[] = [FILE_HEADER]

  // Enums
  for (const e of dmmf.datamodel.enums) {
    sections.push(generateEnum(e))
  }

  // Model interfaces
  for (const model of dmmf.datamodel.models) {
    sections.push(generateModelInterface(model))
  }

  // Resource classes (not exported — used only by RestApiClient)
  for (const model of dmmf.datamodel.models) {
    sections.push(generateResourceClass(model))
  }

  // Top-level client class
  sections.push(generateRestApiClient(dmmf.datamodel.models))

  const content = sections.join('\n\n') + '\n'

  await fs.mkdir(outputDir, { recursive: true })
  await fs.writeFile(path.join(outputDir, 'client.ts'), content, 'utf-8')
}

import type { DMMF } from '@prisma/dmmf'
import { describe, expect, it } from 'vitest'

import { mapScalarToTsType } from './type-mapper'

function field(overrides: Partial<DMMF.Field> & { type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    name: 'field',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  } as DMMF.Field
}

describe('mapScalarToTsType', () => {
  it.each([
    ['String', 'string'],
    ['Boolean', 'boolean'],
    ['Int', 'number'],
    ['Float', 'number'],
    ['DateTime', 'Date'],
    ['Decimal', 'string'],
    ['BigInt', 'string'],
    ['Bytes', 'string'],
    ['Json', 'unknown'],
  ])('maps scalar %s → %s (required)', (prismaType, expected) => {
    expect(mapScalarToTsType(field({ type: prismaType }))).toBe(expected)
  })

  it('appends `| null` for optional scalar fields', () => {
    expect(mapScalarToTsType(field({ type: 'String', isRequired: false }))).toBe('string | null')
  })

  it('wraps in array for list fields', () => {
    expect(mapScalarToTsType(field({ type: 'Int', isList: true }))).toBe('number[]')
  })

  it('does not append null for required list fields', () => {
    expect(mapScalarToTsType(field({ type: 'String', isList: true, isRequired: true }))).toBe('string[]')
  })

  it('returns enum name for enum fields', () => {
    expect(mapScalarToTsType(field({ kind: 'enum', type: 'Role' }))).toBe('Role')
  })

  it('returns model name for relation fields', () => {
    expect(mapScalarToTsType(field({ kind: 'object', type: 'Post' }))).toBe('Post')
  })

  it('returns `unknown` for unsupported fields', () => {
    expect(mapScalarToTsType(field({ kind: 'unsupported', type: 'geometry' }))).toBe('unknown')
  })
})

import type { DMMF } from '@prisma/dmmf'
import { describe, expect, it } from 'vitest'

import { generateModelInterface, generateResourceClass, resourceClassName } from './model-generator'

function makeModel(overrides: Partial<DMMF.Model> & { name: string; fields: DMMF.Field[] }): DMMF.Model {
  return {
    dbName: null,
    schema: null,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
    ...overrides,
  } as DMMF.Model
}

function scalarField(name: string, type: string, opts?: Partial<DMMF.Field>): DMMF.Field {
  return {
    kind: 'scalar',
    name,
    type,
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...opts,
  } as DMMF.Field
}

const userModel = makeModel({
  name: 'User',
  fields: [
    scalarField('id', 'Int', { isId: true, hasDefaultValue: true }),
    scalarField('email', 'String', { isUnique: true }),
    scalarField('name', 'String', { isRequired: false }),
    { kind: 'object', name: 'posts', type: 'Post', isRequired: false, isList: true, isUnique: false, isId: false, isReadOnly: false, hasDefaultValue: false } as DMMF.Field,
  ],
})

describe('resourceClassName', () => {
  it('appends Resource suffix', () => {
    expect(resourceClassName('User')).toBe('UserResource')
    expect(resourceClassName('BlogPost')).toBe('BlogPostResource')
  })
})

describe('generateModelInterface', () => {
  it('emits an export interface with scalar and enum fields only', () => {
    const result = generateModelInterface(userModel)
    expect(result).toContain('export interface User {')
    expect(result).toContain('id: number')
    expect(result).toContain('email: string')
    expect(result).toContain('name?: string | null')
    // relation field should be absent
    expect(result).not.toContain('posts')
  })
})

describe('generateResourceClass', () => {
  it('generates a class named <Model>Resource', () => {
    const result = generateResourceClass(userModel)
    expect(result).toContain('class UserResource {')
  })

  it('contains all five CRUD methods', () => {
    const result = generateResourceClass(userModel)
    expect(result).toContain('async findMany(')
    expect(result).toContain('async findUnique(')
    expect(result).toContain('async create(')
    expect(result).toContain('async update(')
    expect(result).toContain('async delete(')
  })

  it('uses Omit<> on the create input for fields with defaults', () => {
    const result = generateResourceClass(userModel)
    // `id` has hasDefaultValue: true, so it should be omitted
    expect(result).toContain('Omit<User,')
    expect(result).toContain('"id"')
  })

  it('uses the lowercase-plural path in fetch calls', () => {
    const result = generateResourceClass(userModel)
    expect(result).toContain('/users')
  })

  it('uses private class fields (#baseUrl, #headers)', () => {
    const result = generateResourceClass(userModel)
    expect(result).toContain('#baseUrl')
    expect(result).toContain('#headers')
  })
})

