describe('generateRestApiClientFile', () => {
  let tmpDir: string

  beforeEach(async () => {
    tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'rest-api-gen-test-'))
  })

  afterEach(async () => {
    await fs.rm(tmpDir, { recursive: true, force: true })
  })

  it('writes client.ts to the output directory', async () => {
    await generateRestApiClientFile(makeDocument(), tmpDir)
    const files = await fs.readdir(tmpDir)
    expect(files).toContain('client.ts')
  })

  it('includes the file header', async () => {
    await generateRestApiClientFile(makeDocument(), tmpDir)
    const content = await fs.readFile(path.join(tmpDir, 'client.ts'), 'utf-8')
    expect(content).toContain('// Generated by @prisma/client-generator-rest-api')
  })

  it('emits enum types as string unions', async () => {
    await generateRestApiClientFile(makeDocument(), tmpDir)
    const content = await fs.readFile(path.join(tmpDir, 'client.ts'), 'utf-8')
    expect(content).toContain("export type Role = 'ADMIN' | 'USER'")
  })

  it('emits model interfaces', async () => {
    await generateRestApiClientFile(makeDocument(), tmpDir)
    const content = await fs.readFile(path.join(tmpDir, 'client.ts'), 'utf-8')
    expect(content).toContain('export interface User {')
    expect(content).toContain('export interface Post {')
  })

  it('emits resource classes', async () => {
    await generateRestApiClientFile(makeDocument(), tmpDir)
    const content = await fs.readFile(path.join(tmpDir, 'client.ts'), 'utf-8')
    expect(content).toContain('class UserResource {')
    expect(content).toContain('class PostResource {')
  })

  it('emits RestApiClient with per-model accessors', async () => {
    await generateRestApiClientFile(makeDocument(), tmpDir)
    const content = await fs.readFile(path.join(tmpDir, 'client.ts'), 'utf-8')
    expect(content).toContain('export class RestApiClient {')
    expect(content).toContain('readonly user: UserResource')
    expect(content).toContain('readonly post: PostResource')
  })

  it('creates the output directory when it does not exist', async () => {
    const nested = path.join(tmpDir, 'deep', 'nested')
    await generateRestApiClientFile(makeDocument(), nested)
    const content = await fs.readFile(path.join(nested, 'client.ts'), 'utf-8')
    expect(content).toContain('export class RestApiClient {')
  })
})

